mapper.update:
/* 신규 문서 맨 앞 등록을 위한 정렬 순서 증가 myDocuments.incrementSortOrdByUserId */
UPDATE TB_MY_DOC
SET SORT_ORD = SORT_ORD + 1
  , MODIFY_DT = NOW()
WHERE USER_ID = #{userId}

mapper.insert:
/* 나의 문서 보고서 저장 myDocuments.saveReport */
INSERT INTO TB_MY_DOC (
      DOC_ID
    , USER_ID
    , TMPL_ID
    , DOC_NM
    , DOC_HTML
    , ORIGIN_HTML
    , SVC_TY
    , R_CONTENT
    , DOC_STATUS
    , SORT_ORD
    , NEW_YN
    , CREATE_DT
    , MODIFY_DT
) VALUES (
      #{docId}
    , #{userId}
    , #{tmplId, jdbcType=VARCHAR}
    , #{docNm, jdbcType=VARCHAR}
    , #{docHtml, jdbcType=VARCHAR}
    , #{originHtml, jdbcType=VARCHAR}
    , #{svcTy, jdbcType=VARCHAR}
    , #{rContent, jdbcType=VARCHAR}
    , #{docStatus, jdbcType=VARCHAR}
    , #{sortOrd, jdbcType=INTEGER}
    , #{newYn, jdbcType=CHAR}
    , NOW()
    , NOW()
)
ON DUPLICATE KEY UPDATE
      TMPL_ID      = VALUES(TMPL_ID)
    , DOC_NM       = VALUES(DOC_NM)
    , DOC_HTML     = VALUES(DOC_HTML)
    , ORIGIN_HTML  = VALUES(ORIGIN_HTML)
    , SVC_TY       = VALUES(SVC_TY)
    , R_CONTENT    = VALUES(R_CONTENT)
    , DOC_STATUS   = VALUES(DOC_STATUS)
    , SORT_ORD     = COALESCE(#{sortOrd, jdbcType=INTEGER}, SORT_ORD)
    , MODIFY_DT    = NOW()
